'use strict';

// MODULES //

import isObjectLike from '@stdlib/assert-is-object-like';
import { isPrimitive as isNumber } from '@stdlib/assert-is-number';
import { isPrimitive as isString } from '@stdlib/assert-is-string';
import hasProp from '@stdlib/assert-has-property';


// MAIN //

/**
* Tests if a value is an ndarray descriptor.
*
* @param {*} v - value to test
* @returns {boolean} boolean indicating if a value is an ndarray descriptor
*
* @example
* import zeros from '@stdlib/ndarray-zeros';
*
* var bool = isndarrayDescriptor( zeros( [ 2, 2 ] ) );
* // returns true
*
* bool = isndarrayDescriptor( [] );
* // returns false
*/
function isndarrayDescriptor( v ) {
	return (
		// NOTE: intentionally a loose check, as ndarray dtypes can be strings, objects, or other
		(isObjectLike( v ) &&
		isObjectLike( v.data ) &&
		isObjectLike( v.shape ) &&
		isObjectLike( v.strides ) &&
		isNumber( v.offset ) &&
		isString( v.order ) && hasProp( v, 'dtype' ))
	);
}


// EXPORTS //

export default isndarrayDescriptor;
